const stdout = $input.first().json.stdout.trim();
if (!stdout) throw new Error('Saida vazia do Python. Verifique se o python está no PATH do sistema.');

let results;
try {
  results = JSON.parse(stdout);
} catch (e) {
  throw new Error('Falha ao parsear JSON: ' + stdout.substring(0, 300));
}

const items = Array.isArray(results) ? results : [results];
return items.map(item => ({ json: item }));

const BASE = 'C:/Users/Hialagol/Documents/Meus-Projetos/Trabalho-1-Inteligencia-Artificial';

const items = $input.all();
const data = items.map(i => i.json);

const headers = ['id_execucao', 'iterações', 'tempo_ms', 'h_final', 'sucesso', 'reinicios', 'platô', 'ótimo_local', 'estado_inicial', 'estado_final'];

const csvLines = [headers.join(',')];
for (const row of data) {
  const line = headers.map(h => {
    const val = row[h];
    if (Array.isArray(val)) return '"[' + val.join(';') + ']"';
    if (typeof val === 'string') return '"' + val.replace(/"/g, '""') + '"';
    return String(val !== undefined ? val : '');
  }).join(',');
  csvLines.push(line);
}

const fs = require('fs');
const csvPath = BASE + '/resultados/execucoes.csv';
fs.mkdirSync(BASE + '/resultados', { recursive: true });
fs.writeFileSync(csvPath, csvLines.join('\n'), 'utf8');

return [{ json: { execucoes: data, total: data.length, csv_path: csvPath } }];

const BASE = 'C:/Users/Hialagol/Documents/Meus-Projetos/Trabalho-1-Inteligencia-Artificial';

const response = $input.first().json;

let metricas;
try {
  const text = response.candidates[0].content.parts[0].text;
  metricas = typeof text === 'string' ? JSON.parse(text) : text;
} catch(e) {
  throw new Error('Falha ao parsear resposta do Gemini: ' + JSON.stringify(response).substring(0, 300));
}

const fs = require('fs');
fs.writeFileSync(BASE + '/resultados/metricas_gemini.json', JSON.stringify(metricas, null, 2), 'utf8');

return [{ json: metricas }];

const output = $input.first().json.stdout || '';
const success = output.includes('CONCLUIDO');

return [{
  json: {
    pipeline_status: success ? 'SUCESSO - Pipeline completo!' : 'VERIFIQUE O LOG (stdout abaixo)',
    arquivos_gerados: [
      'resultados/execucoes.csv',
      'resultados/metricas_gemini.json',
      'resultados/gerar_graficos.py',
      'resultados/grafico1_sucesso_falha.png',
      'resultados/grafico2_iteracoes_linha.png',
      'resultados/grafico3_histograma_tempo.png',
      'resultados/grafico4_boxplot_iteracoes.png'
    ],
    log_graficos: output.trim()
  }
}];
